import React, { useState, useEffect, useRef, useMemo } from 'react';
import { 
  Send, QrCode, Users, History, Settings, Coins, LogOut, CheckCircle2, 
  AlertCircle, Smartphone, ShieldCheck, LayoutDashboard, ArrowRight, 
  UploadCloud, User, Loader2, Lock, ChevronRight, PlusCircle, CreditCard, 
  Zap, ShoppingBag, Ticket, Image as ImageIcon, Film, X, Database, 
  Activity, Search, Edit, Trash2, MoreVertical, Save, ShieldAlert, 
  TrendingUp, MessageSquare, Server, Plus, Minus, Bell, LogIn, Play, Download,
  RefreshCw, ListPlus, Paperclip, XCircle, Gift, Calendar, Crown, Star
} from 'lucide-react';

const API_URL = 'http://localhost:5000/api';

/* ============================================================================
   CONSTANTS & PRICING
   ============================================================================ */
// Monthly Subscription Packages
const SUBSCRIPTION_PACKAGES = [
  { id: 'sub_1', name: 'Basic Plan', price: 49, credits: 2000, features: ['2,000 Credits per month', 'Basic Support', 'Valid for 30 Days'], icon: Star, popular: false },
  { id: 'sub_2', name: 'Pro Plan', price: 99, credits: 5000, features: ['5,000 Credits per month', 'Priority Support', 'Valid for 30 Days'], icon: Crown, popular: true },
  { id: 'sub_3', name: 'Ultimate Plan', price: 179, credits: 10000, features: ['10,000 Credits per month', 'Dedicated Account Manager', 'Valid for 30 Days'], icon: ShieldCheck, popular: false }
];

// Topup Packages (Add-on / Booster if credits run out)
const TOPUP_PACKAGES = [
  { id: 'tu_1', amount: 500, price: 15, label: 'Lite Reload', icon: Ticket, bonus: null },
  { id: 'tu_2', amount: 1000, price: 28, label: 'Basic Reload', icon: Zap, bonus: '+50 Bonus' },
  { id: 'tu_3', amount: 3000, price: 79, label: 'Pro Reload', icon: Coins, bonus: '+150 Bonus', popular: true },
  { id: 'tu_4', amount: 5000, price: 120, label: 'Enterprise Reload', icon: Database, bonus: '+500 Bonus' }
];

const QRCodeImage = ({ value, size = 200 }) => {
  const qrUrl = `https://quickchart.io/qr?text=${encodeURIComponent(value)}&size=${size}&margin=1`;
  return (
    <div className="bg-white p-4 rounded-3xl shadow-xl border border-slate-100 inline-block">
      <img src={qrUrl} alt="WhatsApp QR" width={size} height={size} className="rounded-xl" />
    </div>
  );
};

/* ============================================================================
   ADMIN PORTAL (LIVE DATABASE INTEGRATION)
   ============================================================================ */
const AdminDashboardPanel = ({ currentUser, onLogout }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');

  // Modal States
  const [editingUser, setEditingUser] = useState(null);
  const [showEditModal, setShowEditModal] = useState(false);
  const [toastMsg, setToastMsg] = useState(null);

  // Edit Form States
  const [editCredits, setEditCredits] = useState(0);
  const [editPlan, setEditPlan] = useState('');
  const [editStatus, setEditStatus] = useState('');

  // Tetapan Sistem
  const [settingsTab, setSettingsTab] = useState('general');
  const [systemSettings, setSystemSettings] = useState({
    maintenanceMode: false,
    allowRegistration: true,
    systemName: 'AR CONNECT',
    apiProvider: 'baileys_md',
    timeout: 30000,
    delayMin: 15,
    delayMax: 35,
  });

  // Tarik data dari database apabila Admin Login
  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/admin/users');
      const data = await response.json();

      const formattedUsers = data.map(u => ({
          id: u._id,
          name: u.nama_syarikat || 'Tiada Nama',
          email: u.email,
          plan: u.plan || 'STARTER',
          credits: u.kredit || 0,
          status: u.status || 'active',
          joined: u.createdAt ? new Date(u.createdAt).toLocaleDateString() : '-'
      }));

      setUsers(formattedUsers);
      setLoading(false);
    } catch (error) {
      console.error("Gagal mendapatkan senarai pengguna:", error);
      setLoading(false);
    }
  };

  const showToast = (msg) => {
    setToastMsg(msg);
    setTimeout(() => setToastMsg(null), 3000);
  };

  const handleSaveUser = async () => {
    try {
        const response = await fetch(`http://localhost:5000/api/admin/users/${editingUser.id}`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                kredit: editCredits,
                plan: editPlan,
                status: editStatus
            })
        });

        const result = await response.json();

        if (result.success) {
            setUsers(users.map(u => {
              if (u.id === editingUser.id) {
                return { ...u, credits: editCredits, plan: editPlan, status: editStatus };
              }
              return u;
            }));
            showToast(`Akaun ${editingUser.name} berjaya dikemas kini!`);
            setShowEditModal(false);
        } else {
            showToast('Gagal mengemas kini pengguna.');
        }
    } catch (error) {
        console.error("Ralat kemas kini:", error);
        showToast('Ralat pelayan.');
    }
  };

  const filteredUsers = useMemo(() => {
    return users.filter(u => 
      u.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
      u.email.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [users, searchQuery]);

  const totalCredits = useMemo(() => users.reduce((acc, curr) => acc + curr.credits, 0), [users]);
  const activeUsersCount = useMemo(() => users.filter(u => u.status === 'active').length, [users]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-800 flex w-full">
      <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col h-screen fixed left-0 top-0">
        <div className="h-20 flex items-center px-6 border-b border-slate-800 bg-slate-950">
          <div className="flex items-center gap-3">
            <div className="bg-emerald-500 p-2 rounded-xl text-white">
              <ShieldAlert size={20} fill="currentColor" />
            </div>
            <div>
              <h1 className="text-white font-black text-lg leading-tight tracking-tight">AR CONNECT</h1>
              <p className="text-[9px] font-bold text-emerald-500 uppercase tracking-widest">Admin Portal</p>
            </div>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <p className="px-4 text-[10px] font-black uppercase tracking-widest text-slate-500 mb-4 mt-4">Main Menu</p>
          {[
            { id: 'dashboard', icon: LayoutDashboard, label: 'Dashboard' },
            { id: 'users', icon: Users, label: 'User Management' },
            { id: 'settings', icon: Settings, label: 'System Settings' },
          ].map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold transition-all text-sm ${
                activeTab === item.id 
                  ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' 
                  : 'hover:bg-slate-800 hover:text-white'
              }`}
            >
              <item.icon size={18} />
              {item.label}
            </button>
          ))}
        </nav>

        <div className="p-4 border-t border-slate-800">
          <div className="flex items-center gap-3 px-4 py-3 mb-2 bg-slate-800 rounded-xl">
            <div className="w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-white font-bold">AD</div>
            <div className="flex-1 overflow-hidden">
              <p className="text-xs font-bold text-white truncate">{currentUser.nama_syarikat || 'Admin'}</p>
              <p className="text-[10px] text-slate-400 truncate">System Administrator</p>
            </div>
          </div>
          <button onClick={onLogout} className="w-full flex items-center justify-center gap-2 px-4 py-3 text-sm font-bold text-red-400 hover:bg-red-500/10 rounded-xl transition-all">
            <LogOut size={16} /> Logout
          </button>
        </div>
      </aside>

      <main className="flex-1 ml-64 flex flex-col h-screen overflow-hidden">
        <header className="h-20 bg-white border-b flex items-center justify-between px-8 sticky top-0 z-10">
          <div><h2 className="text-xl font-black text-slate-800 capitalize">{activeTab === 'users' ? 'User Management' : activeTab}</h2></div>
          <div className="text-sm font-bold text-emerald-600 bg-emerald-50 px-4 py-2 rounded-full border border-emerald-100 flex items-center gap-2">
            <Activity size={16} /> Server Status: Live
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8">
          {activeTab === 'dashboard' && (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-in fade-in">
              <div className="bg-white p-6 rounded-2xl border shadow-sm">
                <p className="text-sm font-bold text-slate-400 mb-1">Total Active Clients</p>
                <h3 className="text-3xl font-black text-slate-800">{loading ? '...' : activeUsersCount}</h3>
              </div>
              <div className="bg-white p-6 rounded-2xl border shadow-sm">
                <p className="text-sm font-bold text-slate-400 mb-1">Total Distributed Credits</p>
                <h3 className="text-3xl font-black text-slate-800">{loading ? '...' : totalCredits.toLocaleString()}</h3>
              </div>
              <div className="bg-white p-6 rounded-2xl border shadow-sm">
                <p className="text-sm font-bold text-slate-400 mb-1">System Core API</p>
                <h3 className="text-3xl font-black text-emerald-500">Online 100%</h3>
              </div>
            </div>
          )}

          {activeTab === 'users' && (
            <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden animate-in fade-in">
              <div className="p-6 border-b flex flex-col sm:flex-row sm:items-center justify-between gap-4 bg-slate-50/50">
                <h3 className="font-black text-lg text-slate-900">Registered Clients Database</h3>
                <div className="relative max-w-md w-full">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                  <input 
                    type="text" 
                    placeholder="Search users by name or email..." 
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-xl focus:outline-none focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500 font-medium text-sm transition-all"
                  />
                </div>
              </div>

              <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                  <thead>
                    <tr className="bg-slate-50 text-slate-500 text-xs uppercase tracking-wider">
                      <th className="p-4 font-black border-y">Client Info</th>
                      <th className="p-4 font-black border-y">Plan</th>
                      <th className="p-4 font-black border-y">Credit Balance</th>
                      <th className="p-4 font-black border-y">Status</th>
                      <th className="p-4 font-black border-y text-right">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100 text-sm">
                    {loading ? (
                      <tr><td colSpan="5" className="p-8 text-center text-slate-400 font-bold">Sedang memuatkan data...</td></tr>
                    ) : filteredUsers.length > 0 ? (
                      filteredUsers.map((user) => (
                        <tr key={user.id} className="hover:bg-slate-50 transition-colors">
                          <td className="p-4">
                            <p className="font-bold text-slate-800 text-sm">{user.name}</p>
                            <p className="text-xs text-slate-500">{user.email}</p>
                          </td>
                          <td className="p-4">
                            <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${
                              user.plan === 'ULTIMATE' ? 'bg-purple-100 text-purple-700' :
                              user.plan === 'PRO' ? 'bg-blue-100 text-blue-700' : 'bg-slate-100 text-slate-700'
                            }`}>{user.plan}</span>
                          </td>
                          <td className="p-4 font-black text-emerald-600">{user.credits.toLocaleString()}</td>
                          <td className="p-4">
                            <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold ${
                              user.status === 'active' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'
                            }`}>
                              <div className={`w-1.5 h-1.5 rounded-full ${user.status === 'active' ? 'bg-emerald-500' : 'bg-red-500'}`}></div>
                              {user.status === 'active' ? 'Active' : 'Suspended'}
                            </span>
                          </td>
                          <td className="p-4 text-right">
                            <button 
                              onClick={() => {
                                setEditingUser(user);
                                setEditCredits(user.credits);
                                setEditPlan(user.plan);
                                setEditStatus(user.status);
                                setShowEditModal(true);
                              }}
                              className="px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg text-xs font-bold hover:bg-emerald-50 hover:text-emerald-600 hover:border-emerald-200 transition-all shadow-sm"
                            >
                              Manage Account
                            </button>
                          </td>
                        </tr>
                      ))
                    ) : (
                      <tr><td colSpan="5" className="p-8 text-center text-slate-400 font-medium">Tiada rekod pengguna dijumpai.</td></tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'settings' && (
             <div className="bg-white p-8 rounded-[2.5rem] border shadow-sm max-w-2xl animate-in fade-in">
              <h3 className="font-black text-xl text-slate-900 border-b pb-4 mb-6">Global System Configuration</h3>
              <p className="text-slate-500 font-medium mb-6">Fungsi konfigurasi sistem akan dihubungkan ke database settings pada fasa seterusnya.</p>

              <div className="space-y-4 opacity-60 pointer-events-none">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-600 uppercase tracking-wide">System Name</label>
                  <input type="text" value={systemSettings.systemName} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold text-slate-800" readOnly />
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-600 uppercase tracking-wide">WhatsApp Core Provider</label>
                  <select value={systemSettings.apiProvider} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold text-slate-800" disabled>
                    <option value="baileys_md">Baileys Multi-Device Engine</option>
                  </select>
                </div>
              </div>
             </div>
          )}
        </div>
      </main>

      {/* Edit Modal Popup */}
      {showEditModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in duration-200">
            <div className="bg-slate-900 px-6 py-4 flex items-center justify-between">
              <h3 className="text-white font-black text-lg">Manage Client Account</h3>
              <button onClick={() => setShowEditModal(false)} className="text-slate-400 hover:text-white transition-colors">
                <X size={20} />
              </button>
            </div>

            <div className="p-6 space-y-6">
              <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 flex items-center justify-between">
                <div>
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Company Name</p>
                  <p className="font-black text-slate-800">{editingUser?.name}</p>
                  <p className="text-sm text-slate-500">{editingUser?.email}</p>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-600 uppercase tracking-wide">Plan</label>
                  <select 
                    value={editPlan} 
                    onChange={(e) => setEditPlan(e.target.value)}
                    className="w-full p-3 bg-white border border-slate-200 rounded-xl font-bold text-slate-800 outline-none focus:border-emerald-500 transition-all"
                  >
                    <option value="STARTER">STARTER</option>
                    <option value="PRO">PRO</option>
                    <option value="ULTIMATE">ULTIMATE</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-600 uppercase tracking-wide">Account Status</label>
                  <select 
                    value={editStatus} 
                    onChange={(e) => setEditStatus(e.target.value)}
                    className="w-full p-3 bg-white border border-slate-200 rounded-xl font-bold text-slate-800 outline-none focus:border-emerald-500 transition-all"
                  >
                    <option value="active">Active</option>
                    <option value="suspended">Suspended (Banned)</option>
                  </select>
                </div>
              </div>

              <div className="space-y-2 pt-4 border-t border-slate-100">
                <label className="text-xs font-bold text-slate-600 uppercase tracking-wide flex justify-between">
                  <span>Credit Balance</span>
                  <span className="text-emerald-500 font-black">{editCredits.toLocaleString()} Units</span>
                </label>
                <input 
                  type="number" 
                  value={editCredits}
                  onChange={(e) => setEditCredits(parseInt(e.target.value) || 0)}
                  className="w-full p-3 bg-white border border-slate-200 rounded-xl font-black text-lg text-slate-800 outline-none focus:border-emerald-500 transition-all"
                />
              </div>
            </div>

            <div className="p-6 bg-slate-50 border-t border-slate-100 flex gap-3">
              <button onClick={() => setShowEditModal(false)} className="flex-1 py-3 bg-white border border-slate-200 text-slate-600 rounded-xl font-bold hover:bg-slate-100 transition-all">
                Cancel
              </button>
              <button onClick={handleSaveUser} className="flex-[2] py-3 bg-emerald-500 text-white rounded-xl font-black hover:bg-emerald-600 transition-all shadow-lg flex items-center justify-center gap-2">
                <Save size={18} /> Update Data
              </button>
            </div>
          </div>
        </div>
      )}

      {toastMsg && (
        <div className="fixed bottom-6 right-6 bg-slate-900 text-white px-6 py-4 rounded-2xl shadow-2xl z-[200] flex items-center gap-3">
          <CheckCircle2 className="text-emerald-500" size={20} />
          <p className="font-bold text-sm">{toastMsg}</p>
        </div>
      )}
    </div>
  );
};

/* ============================================================================
   USER PORTAL (CLIENT) WITH ACTUAL API INTEGRATION (KEKAL ASAL)
   ============================================================================ */
const UserPortal = ({ currentUser, token, onLogout }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [credits, setCredits] = useState(currentUser.kredit || 0);

  // =======================================================================
  // FUNGSI BARU: Tarik profil (kredit & pelan) terus dari backend
  // Ini mengelakkan isu localStorage cache yang menyebabkan kredit tak update
  // =======================================================================
  const syncUserProfile = async () => {
    if (!currentUser?.id) return;
    try {
      const res = await fetch(`${API_URL}/users/${currentUser.id}`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        // Kemas kini state UI dengan nilai paling terkini dari DB
        setCredits(data.kredit !== undefined ? data.kredit : credits);

        // Simpan semula ke sessionStorage supaya kalau user refresh browser, ia tak kembali ke nilai lama
        const savedUser = JSON.parse(sessionStorage.getItem('user') || '{}');
        const updatedUser = { ...savedUser, ...data, id: currentUser.id };
        sessionStorage.setItem('user', JSON.stringify(updatedUser));
      }
    } catch (err) {
      console.warn("Gagal menyelaraskan data profil (sync):", err);
    }
  };

  // Sync data setiap kali pengguna tukar tab / menu (sentiasa live)
  useEffect(() => {
    syncUserProfile();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeTab]);

  // WhatsApp States
  const [isDeviceLinked, setIsDeviceLinked] = useState(false);
  const [qrStatus, setQrStatus] = useState('idle'); 
  const [qr, setQr] = useState(null);
  const isRequesting = useRef(false);

  // Blast States
  const [isBlasting, setIsBlasting] = useState(false);
  const [blastProgress, setBlastProgress] = useState(0);
  const [messagesSent, setMessagesSent] = useState(0);
  const [messagesFailed, setMessagesFailed] = useState(0);
  const [message, setMessage] = useState('');
  const [targetSource, setTargetSource] = useState('manual');
  const [manualNumbers, setManualNumbers] = useState('');
  const [selectedGroup, setSelectedGroup] = useState('all');
  const [messageFormat, setMessageFormat] = useState('text'); 
  const [delayTime, setDelayTime] = useState(2);

  // Media States
  const [mediaFile, setMediaFile] = useState(null);

  // Database Contacts States
  const [contacts, setContacts] = useState([]);
  const [newContact, setNewContact] = useState({ nama: '', nombor_telefon: '', kumpulan: 'General' });
  const [isAddingContact, setIsAddingContact] = useState(false);
  const [isUploadingCSV, setIsUploadingCSV] = useState(false); 
  const [isDeletingAll, setIsDeletingAll] = useState(false);
  const [searchContactQuery, setSearchContactQuery] = useState('');

  // Topup States (Voucher)
  const [voucherCode, setVoucherCode] = useState('');

  // Custom UI Modals States
  const [notification, setNotification] = useState({ show: false, title: '', message: '', type: 'info' });
  const [blastResultModal, setBlastResultModal] = useState({ isOpen: false, success: 0, failed: 0 });

  const uniqueGroups = useMemo(() => {
    const groups = new Set(contacts.map(c => c.kumpulan));
    return Array.from(groups);
  }, [contacts]);

  // Derived state for filtering contacts based on search query
  const displayedContacts = useMemo(() => {
    if (!searchContactQuery) return contacts;
    const lowerQuery = searchContactQuery.toLowerCase();
    return contacts.filter(contact => 
      contact.nama.toLowerCase().includes(lowerQuery) || 
      contact.nombor_telefon.includes(lowerQuery) ||
      contact.kumpulan.toLowerCase().includes(lowerQuery)
    );
  }, [contacts, searchContactQuery]);

  // Helper to show popup warning/info
  const showNotification = (title, message, type = 'info') => {
    setNotification({ show: true, title, message, type });
  };

  const fetchContacts = async () => {
    try {
      const res = await fetch(`${API_URL}/contacts/${currentUser.id}`);
      if (res.ok) {
        const data = await res.json();
        setContacts(data);
      }
    } catch (err) {
      console.error("Failed to load database", err);
    }
  };

  useEffect(() => {
    fetchContacts();
    // eslint-disable-next-line
  }, [activeTab]);

  const handleAddContact = async (e) => {
    e.preventDefault();
    if (!newContact.nombor_telefon) return;

    setIsAddingContact(true);
    try {
      const res = await fetch(`${API_URL}/contacts`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ user_id: currentUser.id, ...newContact })
      });
      if (res.ok) {
        setNewContact({ nama: '', nombor_telefon: '', kumpulan: 'General' });
        fetchContacts();
        showNotification("Success", "New contact has been saved to the database.", "success");
      }
    } catch (err) {
      console.error(err);
      showNotification("Error", "Failed to save contact.", "error");
    } finally {
      setIsAddingContact(false);
    }
  };

  const handleDeleteContact = async (id) => {
    if (!window.confirm("Are you sure you want to delete this contact?")) return;
    try {
