  const handleMediaUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 16 * 1024 * 1024) {
      showNotification("File Too Large", "Media file size exceeds 16MB. Please upload a smaller file.", "warning");
      e.target.value = null;
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      setMediaFile({
        file: file,
        type: file.type,
        name: file.name,
        base64: event.target.result 
      });
    };
    reader.readAsDataURL(file);
    e.target.value = null; 
  };

  const handleFormatChange = (format) => {
