  const startBlast = async () => {
    if (!isDeviceLinked) { 
      showNotification("Session Inactive", "Please connect your WhatsApp (Scan QR) in the Dashboard first.", "warning");
      setActiveTab('dashboard'); 
      return; 
    }

    let numbers = [];
    if (targetSource === 'manual') {
      numbers = manualNumbers.split(/[\n,]+/).map(n => n.trim()).filter(n => n.length > 5);
    } else if (targetSource === 'database') {
      const filteredContacts = selectedGroup === 'all' 
        ? contacts 
        : contacts.filter(c => c.kumpulan === selectedGroup);
      numbers = filteredContacts.map(c => c.nombor_telefon);
    }

    if (numbers.length === 0) {
      showNotification("No Target", "Please enter or select at least one target number.", "warning");
      return;
    }

    if (messageFormat !== 'text' && !mediaFile) {
        showNotification("File Required", `Please upload your ${messageFormat === 'image' ? 'image' : 'video'} file first.`, "warning");
        return;
    }

    if (messageFormat === 'text' && !message) {
      showNotification("Empty Message", "Please enter your campaign message text.", "warning");
      return;
    }

    if (credits < numbers.length) {
      showNotification("Insufficient Credits", `You need ${numbers.length} credit units for this campaign. Current balance: ${credits}.`, "error");
      return;
    }

    setIsBlasting(true); 
    setBlastProgress(0); 
    setMessagesSent(0);
    setMessagesFailed(0);

    let successCount = 0;
    let failCount = 0;
    for (let i = 0; i < numbers.length; i++) {
      try {
        let targetNumber = numbers[i].replace(/[^0-9]/g, '');
        if (targetNumber.startsWith('0')) {
            targetNumber = '6' + targetNumber;
        } else if (targetNumber.startsWith('+')) {
            targetNumber = targetNumber.substring(1);
        }

        const payload = { 
            userId: currentUser.id, 
            to: targetNumber, 
            message: message 
        };
        if (messageFormat !== 'text' && mediaFile) {
            const base64Data = mediaFile.base64.split(',')[1];
            payload.media = base64Data;
            payload.mediaType = mediaFile.type;
            payload.fileName = mediaFile.name;
        }

        const res = await fetch(`${API_URL}/whatsapp/send`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload)
        });
        if (res.ok) {
          successCount++;
          setMessagesSent(successCount);
          setCredits(prev => prev - 1);
        } else {
          failCount++;
          setMessagesFailed(failCount);
          // Silent failure log for admin review
          const errData = await res.json().catch(() => ({}));
          console.error(`[SILENT LOG] Failed to send to ${targetNumber}:`, errData);
        }
      } catch (err) {
        failCount++;
        setMessagesFailed(failCount);
        console.error(`[SILENT LOG] Disconnected from server for number: ${numbers[i]}`, err);
      }
      setBlastProgress(Math.floor(((i + 1) / numbers.length) * 100));
      // MENGGUNAKAN DELAY TIME YANG DIPILIH PENGGUNA
      await new Promise(resolve => setTimeout(resolve, delayTime * 1000));
    }

    setTimeout(() => {
      setIsBlasting(false);
      // Call New Result Modal
      setBlastResultModal({
          isOpen: true,
          success: successCount,
          failed: failCount
      });
    }, 1500);
  };

