/* ============================================================================
   MAIN APP COMPONENT (ACTUAL LOGIN & REGISTRATION MANAGEMENT)
   ============================================================================ */
export default function App() {
  const [currentUser, setCurrentUser] = useState(null);
  const [token, setToken] = useState('');
  const [viewMode, setViewMode] = useState('login');
  const [formData, setFormData] = useState({ email: '', password: '', nama_syarikat: '' });
  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  useEffect(() => {
    // TUKAR: Menggunakan sessionStorage berbanding localStorage
    const savedUser = sessionStorage.getItem('user');
    const savedToken = sessionStorage.getItem('token');
    if (savedUser && savedToken) {
      setCurrentUser(JSON.parse(savedUser));
      setToken(savedToken);
    }
  }, []);

  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    setErrorMsg('');
    setSuccessMsg('');

    const endpoint = viewMode === 'login' ? '/auth/login' : '/auth/register';
    const payload = viewMode === 'login' 
      ? { email: formData.email, kata_laluan: formData.password }
      : { email: formData.email, kata_laluan: formData.password, nama_syarikat: formData.nama_syarikat };

    try {
      const res = await fetch(`${API_URL}${endpoint}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      const data = await res.json();

      if (!res.ok) throw new Error(data.message || 'Something went wrong, please try again.');

      if (viewMode === 'login') {
        // TUKAR: Menyimpan ke sessionStorage supaya sesi spesifik untuk tab tersebut sahaja
        sessionStorage.setItem('token', data.token);
        const userData = { ...data.user, id: data.user.id }; 
        sessionStorage.setItem('user', JSON.stringify(userData));
        setToken(data.token);
        setCurrentUser(userData);
      } else {
        setSuccessMsg('Registration successful! Please log in.');
        setViewMode('login');
      }
    } catch (err) {
      setErrorMsg(err.message);
    } finally {
      setLoading(false);
    }
  };

  const onLogout = () => {
    // TUKAR: Buang data dari sessionStorage apabila log keluar
    sessionStorage.removeItem('user');
    sessionStorage.removeItem('token');
    setCurrentUser(null);
    setToken('');
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 font-sans">
        <div className="w-full max-w-md bg-white rounded-[3rem] shadow-2xl shadow-slate-200 border border-white p-10">
          <div className="text-center mb-10">
            <div className="w-16 h-16 bg-green-500 rounded-2xl flex items-center justify-center mx-auto mb-4 rotate-3 shadow-lg shadow-green-200">
              <Zap size={32} className="text-white fill-current" />

            </div>
            <h1 className="text-3xl font-black tracking-tighter text-slate-900">AR CONNECT</h1>
            <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-1">Fully Connected System</p>
          </div>

          {errorMsg && (
            <div className="p-4 rounded-2xl mb-6 text-xs font-bold flex items-center gap-2 bg-red-50 text-red-500">
              <AlertCircle size={16} /> {errorMsg}
            </div>
          )}
          {successMsg && (
            <div className="p-4 rounded-2xl mb-6 text-xs font-bold flex items-center gap-2 bg-green-50 text-green-500">
              <CheckCircle2 size={16} /> {successMsg}
            </div>
          )}


          <form onSubmit={handleAuth} className="space-y-4">
            {viewMode === 'register' && (
               <div className="space-y-2">
                 <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Company Name</label>
                 <input 

                   type="text" 
                   onChange={(e) => setFormData({...formData, nama_syarikat: e.target.value})} 
                   placeholder="e.g. AR Global" 
                   required 
                   className="w-full p-5 bg-slate-50 rounded-2xl outline-none border-2 border-slate-50 focus:border-green-500 font-bold text-sm transition-all text-slate-800" 
                 />
               </div>
            )}

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email</label>
              <input 
                type="email" 
                onChange={(e) => setFormData({...formData, email: e.target.value})} 
                placeholder="e.g. admin@arconnect.my" 
                required 
                className="w-full p-5 bg-slate-50 rounded-2xl outline-none border-2 border-slate-50 focus:border-green-500 font-bold text-sm transition-all text-slate-800" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Password</label>
              <input 
                type="password" 
                placeholder="••••••••" 
                onChange={(e) => setFormData({...formData, password: e.target.value})}
                required 

                className="w-full p-5 bg-slate-50 rounded-2xl outline-none border-2 border-slate-50 focus:border-green-500 font-bold text-sm transition-all text-slate-800" 
              />
            </div>
            <button disabled={loading} type="submit" className="w-full py-5 bg-green-500 text-white rounded-2xl font-black hover:bg-green-600 transition-all shadow-xl shadow-green-100 mt-4 uppercase tracking-widest flex justify-center items-center gap-2 hover:scale-[1.02] active:scale-95">
              {loading ? <Loader2 className="animate-spin" /> : (viewMode === 'login' ? <LogIn size={20} /> : <PlusCircle size={20} />)} 
              {viewMode === 'login' ? 'Login' : 'Register Account'}
            </button>
          </form>

          <div className="mt-8 text-center">
            <button 
              onClick={() => {
                setErrorMsg('');
                setSuccessMsg('');
                setViewMode(viewMode === 'login' ? 'register' : 'login');
              }}
              className="text-sm font-black text-slate-400 hover:text-green-600 transition-all hover:scale-105"
            >
              {viewMode === 'login' ? "No account? Register now" : "Already have an account? Login"}
            </button>
          </div>
          <p className="text-center text-slate-400 text-[10px] font-black uppercase tracking-[0.2em] mt-10">
            &copy; 2024 AR CONNECT TECHNOLOGY
          </p>
        </div>
      </div>
    );
  }

  // Jika admin login, redirect ke AdminDashboardPanel, jika user biasa pergi ke UserPortal
  if (currentUser.email === 'admin@arconnect.my' || currentUser.role === 'admin') {
    return <AdminDashboardPanel currentUser={currentUser} onLogout={onLogout} />;
  }

  return <UserPortal currentUser={currentUser} token={token} onLogout={onLogout} />;
}
